package gateway

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/gateway"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/gql"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type CustomPostSnapshotResolverProxy struct {
	gateway.UnimplementedCustomPostSnapshotResolverServer
	client gateway.CustomPostSnapshotResolverClient
}

func init() {
	proxyutil.Register(&gateway.CustomPostSnapshotResolver_ServiceDesc, NewCustomPostSnapshotResolverProxy)
}
func NewCustomPostSnapshotResolverProxy(cc grpc.ClientConnInterface) gateway.CustomPostSnapshotResolverServer {
	return &CustomPostSnapshotResolverProxy{client: gateway.NewCustomPostSnapshotResolverClient(cc)}
}
func (p *CustomPostSnapshotResolverProxy) GetCustomPostSnapshot(ctx context.Context, in *gateway.CustomPostSnapshotRequest) (*gql.CustomPostSnapshot, error) {
	return proxyutil.ProxyMethod[gateway.CustomPostSnapshotRequest, gql.CustomPostSnapshot](p.client.GetCustomPostSnapshot)(ctx, in)
}
